1	import { useState } from "react";
2	import { View, Text } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, getDomains } from "../../lib";
5	import "./index.scss";
6	
7	interface HabitWithLogs {
8	  id: string;
9	  title: string;
10	  domainId: string;
11	  frequency: string;
12	  logs: { date: string; completed: boolean }[];
13	}
14	
15	export default function StatsPage() {
16	  const [habits, setHabits] = useState<HabitWithLogs[]>([]);
17	  const [loading, setLoading] = useState(true);
18	  const [range, setRange] = useState<"week" | "month">("week");
19	
20	  useDidShow(() => { fetchStats(); });
21	
22	  async function fetchStats() {
23	    try {
24	      const data = await apiFetch(`/api/stats?range=${range}`);
25	      setHabits(data.habits || []);
26	    } catch {
27	      Taro.showToast({ title: "获取统计数据失败", icon: "none" });
28	    }
29	    setLoading(false);
30	  }
31	
32	  const totalChecks = habits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
33	  const totalPossible = habits.reduce((sum, h) => {
34	    const days = range === "week" ? 7 : 30;
35	    if (h.frequency === "daily") return sum + days;
36	    if (h.frequency === "weekly") return sum + Math.ceil(days / 7);
37	    if (h.frequency === "weekday") return sum + countWeekdays(days);
38	    return sum + days;
39	  }, 0);
40	  const overallRate = totalPossible > 0 ? Math.round((totalChecks / totalPossible) * 100) : 0;
41	
42	  const domainStats = getDomains().map((d) => {
43	    const domainHabits = habits.filter((h) => h.domainId === d.name);
44	    const completed = domainHabits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
45	    const possible = domainHabits.reduce((sum, h) => {
46	      const days = range === "week" ? 7 : 30;
47	      if (h.frequency === "daily") return sum + days;
48	      if (h.frequency === "weekly") return sum + Math.ceil(days / 7);
49	      if (h.frequency === "weekday") return sum + countWeekdays(days);
50	      return sum + days;
51	    }, 0);
52	    return { name: d.name, icon: d.icon, rate: possible > 0 ? Math.round((completed / possible) * 100) : 0, color: d.color };
53	  });
54	
55	  // Bar chart data
56	  const days = range === "week" ? 7 : 30;
57	  const barData = Array.from({ length: days }, (_, i) => {
58	    const d = new Date();
59	    d.setDate(d.getDate() - (days - 1 - i));
60	    const dateStr = d.toISOString().split("T")[0];
61	    const completed = habits.filter((h) => h.logs.some((l) => l.date === dateStr && l.completed)).length;
62	    const maxH = habits.length || 1;
63	    return {
64	      label: d.toLocaleDateString("zh-CN", { day: "numeric" }),
65	      completed,
66	      pct: Math.round((completed / maxH) * 100),
67	    };
68	  });
69	
70	  const streakDays = calcStreak(habits);
71	
72	  return (
73	    <View className="page">
74	      <Text className="page-title">数据统计</Text>
75	      <Text className="page-subtitle">看见进步，持续精进</Text>
76	
77	      <View className="range-tabs">
78	        <Text className={`range-tab ${range === "week" ? "active" : ""}`} onClick={() => { setRange("week"); fetchStats(); }}>本周</Text>
79	        <Text className={`range-tab ${range === "month" ? "active" : ""}`} onClick={() => { setRange("month"); fetchStats(); }}>本月</Text>
80	      </View>
81	
82	      <View className="metrics">
83	        <View className="metric"><Text className="metric-value">{overallRate}%</Text><Text className="metric-label">总完成率</Text></View>
84	        <View className="metric"><Text className="metric-value">{totalChecks}</Text><Text className="metric-label">总打卡数</Text></View>
85	        <View className="metric">
86	          <Text className="metric-value">{streakDays}</Text>
87	          <Text className="metric-label">连续天数</Text>
88	          <Text className="metric-sub">连续精进 {streakDays} 天（完成率≥80%）</Text>
89	        </View>
90	        <View className="metric"><Text className="metric-value">{habits.length}</Text><Text className="metric-label">活跃习惯</Text></View>
91	      </View>
92	
93	      {/* Bar Chart */}
94	      <View className="chart-card">
95	        <Text className="chart-title">每日完成趋势</Text>
96	        <View className="bar-row">
97	          {barData.map((d, i) => (
98	            <View key={i} className="bar-col">
99	              <View className="bar" style={{ height: `${Math.max(d.pct, 4)}%`, background: d.completed > 0 ? "#c4843e" : "#332e28" }} />
100	              <Text className="bar-label">{d.label}</Text>
101	            </View>
102	          ))}
103	        </View>
104	      </View>
105	
106	      {/* Domain Rates */}
107	      <View className="chart-card">
108	        <Text className="chart-title">领域均衡度</Text>
109	        {domainStats.map((d) => (
110	          <View key={d.name} className="domain-row">
111	            <Text className="domain-name">{d.icon} {d.name}</Text>
112	            <View className="domain-bar-bg">
113	              <View className="domain-bar-fill" style={{ width: `${d.rate}%`, background: d.color }} />
114	            </View>
115	            <Text className="domain-rate">{d.rate}%</Text>
116	          </View>
117	        ))}
118	      </View>
119	    </View>
120	  );
121	}
122	
123	function countWeekdays(days: number): number {
124	  let count = 0;
125	  const now = new Date();
126	  for (let i = 0; i < days; i++) {
127	    const d = new Date(now);
128	    d.setDate(d.getDate() - i);
129	    const day = d.getDay();
130	    if (day >= 1 && day <= 5) count++;
131	  }
132	  return count;
133	}
134	
135	function calcStreak(habits: HabitWithLogs[]): number {
136	  if (habits.length === 0) return 0;
137	  const dailyHabits = habits.filter((h) => h.frequency === "daily");
138	  if (dailyHabits.length === 0) return 0;
139	  let streak = 0;
140	  const today = new Date(getToday());
141	  for (let i = 0; ; i++) {
142	    const d = new Date(today);
143	    d.setDate(d.getDate() - i);
144	    const dateStr = d.toISOString().split("T")[0];
145	    let completed = 0;
146	    for (const h of dailyHabits) {
147	      const log = h.logs.find((l) => l.date === dateStr);
148	      if (log && log.completed) completed++;
149	    }
150	    const rate = completed / dailyHabits.length;
151	    if (rate >= 0.8) streak++;
152	    else break;
153	  }
154	  return streak;
155	}
